const cb = $input.item.json;
const msg = (cb.callback_query && cb.callback_query.message) || cb.message || {};
const text = msg.text || '';
const chatId = String(msg.chat?.id || '');
const messageId = msg.message_id;

if (text.includes('ACCEPTÉE')) {
  return { json: { skip: true, chatId, messageId } };
}

const get = (p) => { const m = text.match(p); return m ? m[1].trim() : ''; };
const name = get(/👤 Nom: (.+)/) || 'Client';
const email = get(/📧 Email: (.+)/);
const guests = get(/👥 Convives: (.+)/);
const date = get(/📅 Date: (.+)/);

if (!email || email === 'Non renseigné') {
  return { json: { skip: true, chatId, messageId } };
}

const html = '<div style="font-family:Helvetica Neue,Arial,sans-serif;max-width:600px;margin:0 auto;background:#1a1a1a;border-radius:16px;overflow:hidden;">'
+ '<div style="background:linear-gradient(135deg,#1a1a1a,#2a2218);padding:40px;text-align:center;border-bottom:1px solid rgba(200,169,126,0.3);">'
+ '<h1 style="margin:0;font-size:24px;color:#C8A97E;font-weight:700;letter-spacing:0.05em;">Steak N\' Chill</h1>'
+ '<p style="margin:8px 0 0;color:rgba(255,255,255,0.5);font-size:13px;letter-spacing:0.2em;text-transform:uppercase;">Steakhouse</p>'
+ '</div>'
+ '<div style="padding:40px;">'
+ '<h2 style="margin:0 0 24px;color:#f5f5f5;font-size:20px;">Réservation confirmée !</h2>'
+ '<p style="color:#a0a0a0;font-size:15px;line-height:1.6;margin:0 0 32px;">Bonjour ' + name + ',<br><br>Nous avons le plaisir de vous confirmer votre réservation.</p>'
+ '<div style="padding:24px;background:rgba(200,169,126,0.08);border-radius:12px;border:1px solid rgba(200,169,126,0.2);">'
+ '<table style="width:100%;border-collapse:collapse;">'
+ '<tr><td style="padding:10px 0;color:#C8A97E;font-size:13px;">Date</td><td style="padding:10px 0;color:#f5f5f5;font-size:15px;font-weight:600;text-align:right;">' + date + '</td></tr>'
+ '<tr><td style="padding:10px 0;color:#C8A97E;font-size:13px;">Convives</td><td style="padding:10px 0;color:#f5f5f5;font-size:15px;font-weight:600;text-align:right;">' + guests + '</td></tr>'
+ '</table></div>'
+ '<div style="margin-top:32px;padding:20px;background:rgba(255,255,255,0.03);border-radius:10px;">'
+ '<p style="margin:0 0 8px;color:#C8A97E;font-size:13px;text-transform:uppercase;letter-spacing:0.1em;">Adresse</p>'
+ '<p style="margin:0;color:#f5f5f5;font-size:14px;line-height:1.6;">Bd du Jardin Botanique 7<br>1000 Bruxelles, Belgique</p>'
+ '<p style="margin:12px 0 0;color:#C8A97E;font-size:13px;text-transform:uppercase;letter-spacing:0.1em;">Téléphone</p>'
+ '<p style="margin:4px 0 0;"><a href="tel:+3226755551" style="color:#f5f5f5;text-decoration:none;font-size:14px;">02/675.55.51</a></p>'
+ '</div>'
+ '<p style="margin:32px 0 0;color:#666;font-size:12px;text-align:center;">Nous avons hâte de vous accueillir !</p>'
+ '</div></div>';

const updatedText = text.replace('🥩 NOUVELLE RÉSERVATION', '✅ RÉSERVATION ACCEPTÉE');

return { json: { skip: false, email, name, date, guests, chatId, messageId, subject: 'Réservation confirmée — Steak N\' Chill — ' + date, html, updatedText } };
